utils::globalVariables(c("object", "new_data"))

#' Convert parsnip formulas to the two-column CI response
#'
#' @noRd
.ci_parsnip_formula <- function(formula, data, rank_name, outcome_name) {
  response_vars <- all.vars(formula[[2L]])
  response_call <- formula[[2L]]
  is_ci_response <- is.call(response_call) &&
    identical(as.character(response_call[[1L]]), "cbind") &&
    length(response_vars) >= 2L

  if (is_ci_response) {
    return(list(formula = formula, outcome_name = outcome_name))
  }

  if (!rank_name %in% names(data)) {
    stop("`data` must contain `rank_name` when using a single-outcome formula.",
      call. = FALSE
    )
  }

  actual_outcome_name <- outcome_name
  if (!actual_outcome_name %in% names(data) &&
      length(response_vars) &&
      response_vars[[1L]] %in% names(data)) {
    actual_outcome_name <- response_vars[[1L]]
  }
  if (!actual_outcome_name %in% names(data)) {
    stop(
      "`data` must contain `outcome_name` when using a single-outcome formula.",
      call. = FALSE
    )
  }

  term_labels <- attr(stats::terms(formula, data = data), "term.labels")
  if (identical(term_labels, ".")) {
    predictor_names <- names(data)
  } else {
    predictor_names <- term_labels
  }
  predictor_names <- setdiff(
    predictor_names,
    c(rank_name, outcome_name, actual_outcome_name)
  )
  if (!length(predictor_names)) {
    stop("`formula` must contain at least one predictor besides `rank_name`.",
      call. = FALSE
    )
  }

  rhs <- paste(predictor_names, collapse = " + ")
  formula <- stats::as.formula(
    paste0("cbind(", rank_name, ", ", outcome_name, ") ~ ", rhs),
    env = environment(formula)
  )
  if (!identical(actual_outcome_name, outcome_name)) {
    formula <- stats::as.formula(
      paste0("cbind(", rank_name, ", ", actual_outcome_name, ") ~ ", rhs),
      env = environment(formula)
    )
  }

  list(formula = formula, outcome_name = actual_outcome_name)
}

#' Fit a greedy CI tree from parsnip
#'
#' @description
#' A small wrapper used by the `ineqTrees` parsnip engine for
#' `parsnip::decision_tree()`. The formula can be either the native
#' `cbind(rank, outcome) ~ predictors` response or the usual tidymodels
#' `outcome ~ predictors` response when `rank_name` and `outcome_name` are
#' supplied through `set_engine()`.
#'
#' @param formula A model formula, typically
#'   `cbind(rank, outcome) ~ predictors`.
#' @param data A data frame containing the variables in `formula`.
#' @param weights Optional case weights supplied by parsnip/hardhat.
#' @param rank_name Name of the socioeconomic rank variable.
#' @param outcome_name Name of the outcome variable.
#' @param type One of `"CI"`, `"CIg"`, `"CIc"`, or `"L"`.
#' @param tree_depth Optional parsnip tree-depth value.
#' @param minbucket Minimum weighted child-node size.
#' @param minsplit Minimum weighted parent-node size.
#' @param minprob Minimum child-node weight proportion.
#' @param maxdepth Maximum tree depth. When supplied through `set_engine()`,
#'   this overrides `tree_depth`.
#' @param min_gain Minimum concentration-index gain required to split.
#' @param min_relative_gain Minimum concentration-index gain as a share of the
#'   parent-node impurity required to split.
#' @param na.action Function for handling missing values.
#' @param ... Additional arguments passed to [ci_tree()].
#'
#' @return A fitted `ci_tree` object.
#'
#' @export
ci_tree_parsnip <- function(formula,
                            data,
                            weights = NULL,
                            rank_name = "wealth",
                            outcome_name = "deadu5_num",
                            type = "CIg",
                            tree_depth = NULL,
                            minbucket = 100L,
                            minsplit = 200L,
                            minprob = 0.01,
                            maxdepth = 4L,
                            min_gain = 0,
                            min_relative_gain = 0,
                            na.action = stats::na.omit,
                            ...) {
  if (!is.null(weights)) {
    weights <- as.numeric(weights)
  }

  if (!missing(maxdepth)) {
    depth <- maxdepth
  } else if (!is.null(tree_depth)) {
    depth <- tree_depth
  } else {
    depth <- maxdepth
  }

  control <- ci_tree_control(
    minsplit = as.integer(minsplit),
    minbucket = as.integer(minbucket),
    minprob = minprob,
    maxdepth = as.integer(depth),
    min_gain = min_gain,
    min_relative_gain = min_relative_gain
  )

  prepared <- .ci_parsnip_formula(
    formula = formula,
    data = data,
    rank_name = rank_name,
    outcome_name = outcome_name
  )
  formula <- prepared$formula
  outcome_name <- prepared$outcome_name

  ci_tree(
    formula = formula,
    data = data,
    rank_name = rank_name,
    outcome_name = outcome_name,
    weights = weights,
    type = type,
    control = control,
    na.action = na.action,
    ...
  )
}

#' Fit a greedy CI forest from parsnip
#'
#' @description
#' A small wrapper used by the `ineqTrees` parsnip engine for
#' `parsnip::rand_forest()`.
#'
#' @inheritParams ci_tree_parsnip
#' @param ntree Number of trees to grow.
#' @param mtry Optional number of variables tried at each split.
#' @param perturb Resampling specification passed to [ci_forest()].
#'
#' @return A fitted `ci_forest` object.
#'
#' @export
ci_forest_parsnip <- function(formula,
                              data,
                              weights = NULL,
                              rank_name = "wealth",
                              outcome_name = "deadu5_num",
                              type = "CIg",
                              ntree = 500L,
                              mtry = NULL,
                              minbucket = 100L,
                              minsplit = 200L,
                              minprob = 0.01,
                              maxdepth = 4L,
                              min_gain = 0,
                              min_relative_gain = 0,
                              perturb = list(replace = FALSE, fraction = 0.632),
                              na.action = stats::na.omit,
                              ...) {
  if (!is.null(weights)) {
    weights <- as.numeric(weights)
  }

  control <- ci_tree_control(
    minsplit = as.integer(minsplit),
    minbucket = as.integer(minbucket),
    minprob = minprob,
    maxdepth = as.integer(maxdepth),
    min_gain = min_gain,
    min_relative_gain = min_relative_gain
  )

  prepared <- .ci_parsnip_formula(
    formula = formula,
    data = data,
    rank_name = rank_name,
    outcome_name = outcome_name
  )
  formula <- prepared$formula
  outcome_name <- prepared$outcome_name

  ci_forest(
    formula = formula,
    data = data,
    rank_name = rank_name,
    outcome_name = outcome_name,
    weights = weights,
    type = type,
    control = control,
    ntree = as.integer(ntree),
    mtry = mtry,
    perturb = perturb,
    na.action = na.action,
    ...
  )
}

#' Register `ineqTrees` parsnip engines
#'
#' @description
#' Registers `ineqTrees` as a regression engine for
#' `parsnip::decision_tree()` and `parsnip::rand_forest()`.
#'
#' @return Invisibly, `TRUE`.
#'
#' @examples
#' if (requireNamespace("parsnip", quietly = TRUE)) {
#'   register_ineqtrees_parsnip()
#' }
#'
#' @export
register_ineqtrees_parsnip <- function() {
  register_ineqtrees_decision_tree()
  register_ineqtrees_rand_forest()
  invisible(TRUE)
}

#' Register the `decision_tree()` `ineqTrees` engine
#'
#' @return Invisibly, `TRUE`.
#'
#' @export
register_ineqtrees_decision_tree <- function() {
  if (!any(parsnip::show_engines("decision_tree")$engine == "ineqTrees")) {
    parsnip::set_model_engine(
      model = "decision_tree",
      mode = "regression",
      eng = "ineqTrees"
    )
  }

  parsnip::set_dependency("decision_tree", eng = "ineqTrees", pkg = "ineqTrees")

  parsnip::set_model_arg(
    model = "decision_tree",
    eng = "ineqTrees",
    parsnip = "tree_depth",
    original = "tree_depth",
    func = list(pkg = "dials", fun = "tree_depth"),
    has_submodel = FALSE
  )

  parsnip::set_model_arg(
    model = "decision_tree",
    eng = "ineqTrees",
    parsnip = "min_n",
    original = "minbucket",
    func = list(pkg = "dials", fun = "min_n"),
    has_submodel = FALSE
  )

  parsnip::set_encoding(
    model = "decision_tree",
    mode = "regression",
    eng = "ineqTrees",
    options = list(
      predictor_indicators = "none",
      compute_intercept = FALSE,
      remove_intercept = FALSE,
      allow_sparse_x = FALSE
    )
  )

  parsnip::set_fit(
    model = "decision_tree",
    mode = "regression",
    eng = "ineqTrees",
    value = list(
      interface = "formula",
      data = c(formula = "formula", data = "data", weights = "weights"),
      protect = c("formula", "data", "weights"),
      func = c(pkg = "ineqTrees", fun = "ci_tree_parsnip"),
      defaults = list()
    )
  )

  parsnip::set_pred(
    model = "decision_tree",
    mode = "regression",
    eng = "ineqTrees",
    type = "numeric",
    value = list(
      pre = NULL,
      post = function(results, object) {
        tibble::tibble(.pred = as.numeric(results))
      },
      func = c(fun = "predict"),
      args = list(
        object = rlang::expr(object$fit),
        newdata = rlang::expr(new_data),
        type = "response"
      )
    )
  )

  parsnip::set_pred(
    model = "decision_tree",
    mode = "regression",
    eng = "ineqTrees",
    type = "raw",
    value = list(
      pre = NULL,
      post = function(results, object) {
        tibble::tibble(.node = as.integer(results))
      },
      func = c(fun = "predict"),
      args = list(
        object = rlang::expr(object$fit),
        newdata = rlang::expr(new_data),
        type = "node"
      )
    )
  )

  invisible(TRUE)
}

